 43→	const cliParams = getCliParams();
 44→	const { resolvedTheme } = useTheme();
 45→	const logoSrc =
 46→		resolvedTheme === "dark" ? "/logo-light.svg" : "/logo-dark.svg";
 47→
 48→	useEffect(() => {
