 50→		setCliRedirecting(true);
 51→
 52→		fetch("/api/cli-token", { credentials: "include" })
 53→			.then((res) => res.json())
 54→			.then((data: { token: string }) => {
 55→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 56→				window.location.href = redirectUrl;
 57→			});
 58→	}, [session, cliParams, cliRedirecting]);
 59→
 60→	if (isPending) {
