 1→import { useMemo } from "react";
 2→import type {
 3→	Conversation,
 4→	ToolResultContent,
 5→} from "@/lib/conversation-schema";
 6→import { parseConversations } from "@/lib/conversation-schema";
 7→
 8→interface Session {
 9→	content: string;
10→	subagents: Record<string, string>;
11→}
12→
13→function isToolResult(
14→	block: string | { type: "text"; text: string } | ToolResultContent,
15→): block is ToolResultContent {
16→	return typeof block === "object" && block.type === "tool_result";
17→}
18→
19→export function useSession(session: Session) {
20→	const { conversations, toolResultMap } = useMemo(() => {
21→		const parsed = parseConversations(session.content);
22→		const resultMap = new Map<string, ToolResultContent>();
23→
24→		// Build tool result map from user entries
25→		for (const conv of parsed) {
26→			if (conv.type === "user" && Array.isArray(conv.message.content)) {
27→				for (const block of conv.message.content) {
28→					if (isToolResult(block)) {
29→						resultMap.set(block.tool_use_id, block);
30→					}
31→				}
32→			}
33→		}
34→
35→		return { conversations: parsed, toolResultMap: resultMap };
36→	}, [session.content]);
37→
38→	const getToolResult = (toolUseId: string) => toolResultMap.get(toolUseId);
39→
40→	const subagents = useMemo(() => {
41→		const result = new Map<string, Array<Conversation>>();
42→		for (const [agentId, content] of Object.entries(session.subagents)) {
43→			result.set(agentId, parseConversations(content));
44→		}
45→		return result;
46→	}, [session.subagents]);
47→
48→	return { conversations, getToolResult, subagents };
49→}
